Text( text = "Create Account", style = MaterialTheme.typography.headlineLarge.copy( fontWeight = FontWeight.Bold, letterSpacing = 0.5.sp ), color = MaterialTheme.colorScheme.primary ) Text( text = "Join us to manage waste smartly", style = MaterialTheme.typography.bodyLarge, color = MaterialTheme.colorScheme.onSurfaceVariant )
Spacer(modifier = Modifier.height(32.dp))
OutlinedTextField( value = name, onValueChange = { name = it }, label = { Text("Full Name") }, leadingIcon = { Icon(Icons.Default.Person, contentDescription = null, tint = MaterialTheme.colorScheme.primary) }, modifier = Modifier.fillMaxWidth(), shape = RoundedCornerShape(16.dp), singleLine = true, keyboardOptions = KeyboardOptions( keyboardType = KeyboardType.Text, imeAction = ImeAction.Next ), colors = OutlinedTextFieldDefaults.colors( focusedBorderColor = MaterialTheme.colorScheme.primary, unfocusedBorderColor = MaterialTheme.colorScheme.outlineVariant ) )
Spacer(modifier = Modifier.height(12.dp))
OutlinedTextField( value = email, onValueChange = { email = it }, label = { Text("Email Address") }, leadingIcon = { Icon(Icons.Default.Email, contentDescription = null, tint = MaterialTheme.colorScheme.primary) }, modifier = Modifier.fillMaxWidth(), shape = RoundedCornerShape(16.dp), keyboardOptions = KeyboardOptions( keyboardType = KeyboardType.Email, imeAction = ImeAction.Next ), singleLine = true, colors = OutlinedTextFieldDefaults.colors( focusedBorderColor = MaterialTheme.colorScheme.primary, unfocusedBorderColor = MaterialTheme.colorScheme.outlineVariant ) )
Spacer(modifier = Modifier.height(12.dp))
Row(modifier = Modifier.fillMaxWidth()) { OutlinedTextField( value = age, onValueChange = { if (it.length <= 3 && it.all { char -> char.isDigit() }) age = it }, label = { Text("Age") }, leadingIcon = { Icon(Icons.Default.DateRange, contentDescription = null, tint = MaterialTheme.colorScheme.primary) }, modifier = Modifier.weight(1f), shape = RoundedCornerShape(16.dp), keyboardOptions = KeyboardOptions( keyboardType = KeyboardType.Number, imeAction = ImeAction.Next ), singleLine = true, colors = OutlinedTextFieldDefaults.colors( focusedBorderColor = MaterialTheme.colorScheme.primary, unfocusedBorderColor = MaterialTheme.colorScheme.outlineVariant ) ) Spacer(modifier = Modifier.width(12.dp)) OutlinedTextField( value = phone, onValueChange = { if (it.length <= 15 && it.all { char -> char.isDigit() || char == '+' }) phone = it }, label = { Text("Phone") }, leadingIcon = { Icon(Icons.Default.Phone, contentDescription = null, tint = MaterialTheme.colorScheme.primary) }, modifier = Modifier.weight(2f), shape = RoundedCornerShape(16.dp), keyboardOptions = KeyboardOptions( keyboardType = KeyboardType.Phone, imeAction = ImeAction.Next ), singleLine = true, colors = OutlinedTextFieldDefaults.colors( focusedBorderColor = MaterialTheme.colorScheme.primary, unfocusedBorderColor = MaterialTheme.colorScheme.outlineVariant ) ) }
Spacer(modifier = Modifier.height(12.dp))
Card( modifier = Modifier.fillMaxWidth(), shape = RoundedCornerShape(16.dp), colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f)) ) { Column(modifier = Modifier.padding(16.dp)) { Text("Gender", style = MaterialTheme.typography.labelLarge, color = MaterialTheme.colorScheme.primary) Row(verticalAlignment = Alignment.CenterVertically) { RadioButton(selected = gender == "Male", onClick = { gender = "Male" }) Text("Male") Spacer(modifier = Modifier.width(16.dp)) RadioButton(selected = gender == "Female", onClick = { gender = "Female" }) Text("Female") } } }
Spacer(modifier = Modifier.height(12.dp))
OutlinedTextField( value = password, onValueChange = { password = it }, label = { Text("Password") }, leadingIcon = { Icon(Icons.Default.Lock, contentDescription = null, tint = MaterialTheme.colorScheme.primary) }, trailingIcon = { val image = if (passwordVisible) Icons.Default.Visibility else Icons.Default.VisibilityOff IconButton(onClick = { passwordVisible = !passwordVisible }) { Icon(imageVector = image, contentDescription = if (passwordVisible) "Hide password" else "Show password") } }, visualTransformation = if (passwordVisible) VisualTransformation.None else PasswordVisualTransformation(), modifier = Modifier.fillMaxWidth(), shape = RoundedCornerShape(16.dp), keyboardOptions = KeyboardOptions( keyboardType = KeyboardType.Password, imeAction = ImeAction.Done ), keyboardActions = KeyboardActions( onDone = { focusManager.clearFocus() } ), singleLine = true, colors = OutlinedTextFieldDefaults.colors( focusedBorderColor = MaterialTheme.colorScheme.primary, unfocusedBorderColor = MaterialTheme.colorScheme.outlineVariant ) )
viewModel.error.value?.let { error -> Text( text = error, color = MaterialTheme.colorScheme.error, style = MaterialTheme.typography.bodySmall, modifier = Modifier.padding(top = 8.dp).align(Alignment.Start) ) }
Spacer(modifier = Modifier.height(32.dp))
if (viewModel.isLoading.value) { CircularProgressIndicator(color = MaterialTheme.colorScheme.primary) } else { Button( onClick = { viewModel.signUp(name, email, age, phone, gender, password, onSignupSuccess) }, modifier = Modifier .fillMaxWidth() .height(56.dp), shape = RoundedCornerShape(16.dp), elevation = ButtonDefaults.buttonElevation(defaultElevation = 4.dp) ) { Text("Sign Up", fontSize = 18.sp, fontWeight = FontWeight.Bold) }
Spacer(modifier = Modifier.height(24.dp))
TextButton(onClick = onNavigateToLogin) { Text( text = "Already have an account? Login", color = MaterialTheme.colorScheme.primary, fontWeight = FontWeight.Bold ) } } } } }

